async function transferMoney(fromAccount, toAccount, amount, currency = "USD") {
  if (!fromAccount || !toAccount) throw new Error("Both accounts required");
  if (fromAccount === toAccount) throw new Error("Cannot transfer to same account");
  if (amount <= 0) throw new Error("Amount must be positive");
  if (amount > 1000000) throw new Error("Amount exceeds limit");
  const rate = await getExchangeRate(currency, "USD");
  const usdAmount = amount * rate;
  const balance = await getBalance(fromAccount);
  if (balance < usdAmount) throw new Error("Insufficient funds");
  await debit(fromAccount, usdAmount);
  try {
    await credit(toAccount, usdAmount);
  } catch (e) {
    await credit(fromAccount, usdAmount);
    throw new Error("Transfer failed: " + e.message);
  }
  return { fromAccount, toAccount, amount, currency, usdAmount, newBalance: balance - usdAmount };
}",
