PR Code:
class ApiClient {
  constructor(baseUrl, maxRetries = 3) {
    this.baseUrl = baseUrl;
    this.maxRetries = maxRetries;
  }
  async request(method, path, body) {
    let lastError;
    for (let attempt = 0; attempt <= this.maxRetries; attempt++) {
      try {
        const resp = await fetch(this.baseUrl + path, {
          method,
          headers: { "Content-Type": "application/json" },
          body: body ? JSON.stringify(body) : undefined,
        });
        if (resp.status >= 500) throw new Error(`Server error: ${resp.status}`);
        if (resp.status === 429) {
          await this.sleep(1000 * attempt);
          continue;
        }
        return await resp.json();
      } catch (e) {
        lastError = e;
        if (attempt < this.maxRetries) await this.sleep(1000 * Math.pow(2, attempt));
      }
    }
    throw lastError;
  }
  sleep(ms) { return new Promise(r => setTimeout(r, ms)); }
}",
      "agentId": "correctness-reviewer"
    },
    {
      "prompt": "You are reviewing the same PR focused on ROBUSTNESS. Check: 1) Network timeouts? 2) Non-JSON responses? 3) Should 4xx retry? 4) AbortController? 5) Concurrent limits? Add issues the first reviewer missed.",
